#include <concepts>
#include <iostream>
#include <string>

template<typename T>
concept Printable = requires(T x) {
    { x.to_string() } -> std::convertible_to<std::string>;
};

struct Point {
    int x, y;
    std::string to_string() const {
        return "(" + std::to_string(x) + ", " + std::to_string(y) + ")";
    }
};

struct Opaque { int data; }; // no to_string()

template<Printable T>
void print_item(const T& item) {
    std::cout << "item: " << item.to_string() << "\n";
}

int main() {
    print_item(Point{3, 4});
    // print_item(Opaque{42}); // would not compile

    std::cout << "Point satisfies Printable: " << std::boolalpha << Printable<Point> << "\n";
    std::cout << "Opaque satisfies Printable: " << Printable<Opaque> << "\n";
}

#include <concepts>
#include <iostream>

template<std::integral T>
T double_it(T x) { return x * 2; }

template<std::floating_point T>
T double_it(T x) { return x * 2.0; }

template<std::totally_ordered T>
T clamp(T val, T lo, T hi) {
    if (val < lo) return lo;
    if (val > hi) return hi;
    return val;
}

int main() {
    std::cout << "double_it(5): " << double_it(5) << "\n";
    std::cout << "double_it(2.5): " << double_it(2.5) << "\n";
    std::cout << "clamp(15, 0, 10): " << clamp(15, 0, 10) << "\n";
    std::cout << "clamp(-3, 0, 10): " << clamp(-3, 0, 10) << "\n";

    std::cout << std::boolalpha;
    std::cout << "int is integral: " << std::integral<int> << "\n";
    std::cout << "double is integral: " << std::integral<double> << "\n";
    std::cout << "int is regular: " << std::regular<int> << "\n";
}

#include <concepts>
#include <cstddef>
#include <iostream>
#include <string>
#include <vector>

template<typename T>
concept Container = requires(T c, const T cc) {
    // Simple: operation must be valid
    c.begin();
    c.end();
    // Compound: must return convertible type
    { cc.size() } -> std::convertible_to<std::size_t>;
    { cc.empty() } -> std::same_as<bool>;
    // Type requirement: nested type must exist
    typename T::value_type;
    // Nested: another concept must be satisfied
    requires std::copyable<typename T::value_type>;
};

template<Container C>
void describe(const C& c) {
    std::cout << "size: " << c.size() << ", empty: " << std::boolalpha << c.empty() << "\n";
}

int main() {
    std::vector<int> v = {1, 2, 3};
    describe(v);

    std::cout << std::boolalpha;
    std::cout << "vector<int> is Container: " << Container<std::vector<int>> << "\n";
    std::cout << "int is Container: " << Container<int> << "\n";
    std::cout << "string is Container: " << Container<std::string> << "\n";
}
